css:
.print-heading {
  text-align: center;
  margin-bottom: 30px;
}

.print-heading h2 {
  margin: 0;
  font-size: 18pt;
}

.ppe-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #ddd;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 20px;
}

.ppe-table th,
.ppe-table td {
  padding: 8px;
}

.ppe-table th {
  background-color: #f5f5f5;
  border-bottom: 1px solid #ddd;
}

.ppe-table td {
  border-bottom: 1px solid #ddd;
  border-right: 1px solid #ddd;
}

.ppe-table td:last-child,
.ppe-table th:last-child {
  border-right: none;
}

.ppe-table tbody tr:last-child td {
  border-bottom: none;
}

.ppe-table tbody tr:nth-child(odd) {
  background-color: #fafafa;
}
